import csv
import json
import logging
import re
import warnings
from datetime import datetime, timezone
from html import unescape
from io import StringIO
from math import ceil
from urllib.parse import urljoin

import requests
from osm2geojson import json2geojson

from .errors import (
    MultipleRequestsError,
    OverpassSyntaxError,
    ServerLoadError,
    ServerRuntimeError,
    TimeoutError,
    UnknownOverpassError,
)

DEFAULT_USER_AGENT = "Unknown overpass-api-python-wrapper application"


class API:
    """A simple Python wrapper for the OpenStreetMap Overpass API.

    :param user_agent: A required User-Agent value to identify your client (application name
                       and an email address).
    :param timeout: If a single number, the TCP connection timeout for the request. If a tuple
                    of two numbers, the connection timeout and the read timeout respectively.
                    Timeouts can be integers or floats.
    :param endpoint: URL of overpass interpreter
    :param headers: HTTP headers to include when making requests to the overpass endpoint.
                    The user_agent value will be added automatically, and should not be included
                    here.
    :param debug: Boolean to turn on debugging output
    :param proxies: Dictionary of proxies to pass to the request library. See
                    requests documentation for details.
    :param status_url: Override URL for the status endpoint. If not provided, it is derived
                       from ``endpoint`` by replacing the last path component with ``status``.
    """

    SUPPORTED_FORMATS = ("geojson", "json", "xml", "csv")

    # defaults for the API class
    _timeout = 25  # second
    _endpoint = "https://overpass-api.de/api/interpreter"
    _headers = {"Accept-Charset": "utf-8;q=0.7,*;q=0.7"}
    _debug = False
    _proxies = None

    _QUERY_TEMPLATE = "[out:{out}]{date};{query}out {verbosity};"
    _GEOJSON_QUERY_TEMPLATE = "[out:json]{date};{query}out {verbosity};"
    _DEFAULT_RESPONSEFORMAT = object()
    _DEFAULT_VERBOSITY = object()
    _DEFAULT_BUILD = object()

    def __init__(
        self,
        user_agent: str = DEFAULT_USER_AGENT,
        endpoint: str = _endpoint,
        headers: dict | None = None,
        timeout: int | float | tuple = _timeout,
        debug: bool = _debug,
        proxies: dict | None = _proxies,
        status_url: str | None = None,
    ):
        warnings.warn(
            "overpass.API is deprecated and will be removed in overpass 1.0; "
            "use overpass.OverpassClient in 1.0 instead.",
            DeprecationWarning,
            stacklevel=2,
        )
        if debug:
            warnings.warn(
                "overpass.API(debug=True) is deprecated and will be removed in "
                "overpass 1.0; use OverpassClient(log_queries=True) in 1.0 instead.",
                DeprecationWarning,
                stacklevel=2,
            )

        self.endpoint = endpoint
        self.headers = self._headers.copy() if headers is None else headers
        self.headers["User-Agent"] = user_agent
        self.timeout = timeout
        self.debug = debug
        self.proxies = proxies
        self._status = None
        self.log = logging.getLogger(__name__)

        # Derive status URL from endpoint by replacing the last path component
        # with "status", unless an explicit override is given.
        if status_url is not None:
            self.status_url = status_url
        else:
            # urljoin with a sibling-relative path replaces the last segment.
            # e.g. "https://overpass-api.de/api/interpreter" -> "https://overpass-api.de/api/status"
            self.status_url = urljoin(endpoint + "/", "../status")

        if self.debug:
            from http.client import HTTPConnection

            HTTPConnection.debuglevel = 1

            self.log.setLevel(logging.DEBUG)

            requests_log = logging.getLogger("urllib3")
            requests_log.setLevel(logging.DEBUG)
            requests_log.propagate = True

    def get(
        self,
        query,
        responseformat=_DEFAULT_RESPONSEFORMAT,
        verbosity=_DEFAULT_VERBOSITY,
        build=_DEFAULT_BUILD,
        date="",
    ):
        """Pass in an Overpass query in Overpass QL.

        :param query: the Overpass QL query to send to the endpoint
        :param responseformat: one of the supported output formats ["geojson", "json", "xml", "csv"]
        :param verbosity: one of the supported levels out data verbosity ["ids",
                          "skel", "body", "tags", "meta"] and optionally modifiers ["geom", "bb",
                          "center"] followed by an optional sorting indicator ["asc", "qt"]. Example:
                          "body geom qt"
        :param build: boolean to indicate whether to build the overpass query from a template (True)
                          or allow the programmer to specify full query manually (False)
        :param date: a date with an optional time. Example: 2020-04-27 or 2020-04-27T00:00:00Z
        """
        if responseformat is not self._DEFAULT_RESPONSEFORMAT:
            warnings.warn(
                "API.get(responseformat=...) is deprecated and will be replaced by "
                "OverpassClient.query(..., output=...) in overpass 1.0.",
                DeprecationWarning,
                stacklevel=2,
            )
        else:
            responseformat = "geojson"

        if verbosity is not self._DEFAULT_VERBOSITY:
            warnings.warn(
                "API.get(verbosity=...) is deprecated and will be replaced by "
                "OverpassClient.query(..., out=...) in overpass 1.0.",
                DeprecationWarning,
                stacklevel=2,
            )
        else:
            verbosity = "body"

        if build is not self._DEFAULT_BUILD:
            warnings.warn(
                "API.get(build=...) is deprecated and will be replaced by "
                "OverpassClient.query_raw(...) for full Overpass QL in overpass 1.0.",
                DeprecationWarning,
                stacklevel=2,
            )
        else:
            build = True

        self._validate_responseformat(responseformat)

        if date and isinstance(date, str):
            # If date is given and is not already a datetime, attempt to parse from string
            date_string = date
            try:
                date = datetime.fromisoformat(date_string)
            except ValueError:
                # The 'Z' in a standard overpass date will throw fromisoformat() off
                date = datetime.strptime(date_string, "%Y-%m-%dT%H:%M:%SZ")
        # Construct full Overpass query
        if build:
            full_query = self._construct_ql_query(
                query, responseformat=responseformat, verbosity=verbosity, date=date
            )
        else:
            full_query = query

        self.log.debug(query)

        # Get the response from Overpass
        r = self._get_from_overpass(full_query)
        content_type = r.headers.get("content-type")
        content_type_name = self._content_type_name(content_type)
        self.log.debug(content_type)

        if content_type_name == "text/csv":
            return list(csv.reader(StringIO(r.text), delimiter="\t"))
        elif content_type_name in (
            "text/xml",
            "application/xml",
            "application/osm3s+xml",
        ):
            return r.text
        elif content_type_name in ("text/html", "application/xhtml+xml"):
            error_message = self._extract_html_error_message(r.text)
            if error_message and error_message.casefold().startswith("runtime error"):
                raise ServerRuntimeError(error_message)
            if error_message:
                raise UnknownOverpassError(error_message)
            raise UnknownOverpassError("Received an HTML error response from Overpass.")
        else:
            response = json.loads(r.text)

        if not build:
            return response

        # Check for valid answer from Overpass.
        # A valid answer contains an 'elements' key at the root level.
        if "elements" not in response:
            raise UnknownOverpassError("Received an invalid answer from Overpass.")

        # If there is a 'remark' key, it spells trouble.
        overpass_remark = response.get("remark", None)
        if overpass_remark and overpass_remark.startswith("runtime error"):
            raise ServerRuntimeError(overpass_remark)

        if responseformat != "geojson":
            return response

        # construct geojson
        return json2geojson(response)

    @staticmethod
    def _content_type_name(content_type: str | None) -> str:
        if content_type is None:
            return ""
        return content_type.split(";", 1)[0].strip().lower()

    @staticmethod
    def _extract_html_error_message(response_text: str) -> str | None:
        response_body = re.sub(r"<[^>]+>", " ", response_text)
        normalized_text = re.sub(r"\s+", " ", unescape(response_body)).strip()

        runtime_error_match = re.search(
            r"(runtime error:\s+.+)", normalized_text, re.IGNORECASE
        )
        if runtime_error_match is not None:
            return runtime_error_match.group(1).strip()

        error_match = re.search(r"\bError\b:?\s*(.+)", normalized_text, re.IGNORECASE)
        if error_match is not None:
            return error_match.group(1).strip()

        return None

    def _api_status(self) -> dict:
        """
        :returns: dict describing the client's status with the API
        """
        status_headers = {"User-Agent": self.headers["User-Agent"]}
        r = requests.get(
            url=self.status_url, proxies=self.proxies, headers=status_headers
        )
        lines = tuple(r.text.splitlines())

        available_re = re.compile(r"\d(?= slots? available)")
        available_slots = int(
            next((m.group() for line in lines if (m := available_re.search(line))), 0)
        )

        waiting_re = re.compile(r"(?<=Slot available after: )[\d\-TZ:]{20}")
        waiting_slots = tuple(
            datetime.strptime(m.group(), "%Y-%m-%dT%H:%M:%S%z")
            for line in lines
            if (m := waiting_re.search(line))
        )

        # Find the index of the "Currently running queries" header.
        # If the header is absent the running queries list is empty — do not
        # raise StopIteration as the old next(...) without a default did.
        current_idx = next(
            (
                i
                for i, word in enumerate(lines)
                if word.startswith("Currently running queries")
            ),
            None,
        )
        if current_idx is None:
            running_slots_datetimes: tuple = ()
        else:
            running_slots_datetimes = tuple(
                datetime.strptime(parts[3], "%Y-%m-%dT%H:%M:%S%z")
                for line in lines[current_idx + 1 :]
                if line.strip() and len(parts := line.split()) >= 4
            )

        return {
            "available_slots": available_slots,
            "waiting_slots": waiting_slots,
            "running_slots": running_slots_datetimes,
        }

    @property
    def slots_available(self) -> int:
        """
        :returns: count of open slots the client has on the server
        """
        return self._api_status()["available_slots"]

    @property
    def slots_waiting(self) -> tuple:
        """
        :returns: tuple of datetimes representing waiting slots and when they will be available
        """
        return self._api_status()["waiting_slots"]

    @property
    def slots_running(self) -> tuple:
        """
        :returns: tuple of datetimes representing running slots and when they will be freed
        """
        return self._api_status()["running_slots"]

    @property
    def slot_available_datetime(self) -> datetime | None:
        """
        :returns: None if a slot is available now (no wait needed) or a datetime representing when the next slot will become available
        """
        if self.slots_available:
            return None
        return min(self.slots_running + self.slots_waiting)

    @property
    def slot_available_countdown(self) -> int:
        """
        :returns: 0 if a slot is available now, or an int of seconds until the next slot is free
        """
        available_datetime = self.slot_available_datetime
        if available_datetime is None:
            return 0

        return max(
            ceil((available_datetime - datetime.now(timezone.utc)).total_seconds()),
            0,
        )

    def search(self, feature_type, regex=False):
        """Search for something."""
        raise NotImplementedError()

    def Get(self, *args, **kwargs):
        """Deprecated uppercase alias for :meth:`get`."""
        warnings.warn(
            "API.Get(...) is deprecated and will be removed in overpass 1.0; "
            "use API.get(...) on 0.8.x or OverpassClient.query(...) in 1.0.",
            DeprecationWarning,
            stacklevel=2,
        )
        return self.get(*args, **kwargs)

    def Search(self, *args, **kwargs):
        """Deprecated uppercase alias for :meth:`search`."""
        warnings.warn(
            "API.Search(...) is deprecated and will be removed in overpass 1.0; "
            "use API.search(...) on 0.8.x.",
            DeprecationWarning,
            stacklevel=2,
        )
        return self.search(*args, **kwargs)

    @classmethod
    def _validate_responseformat(cls, responseformat):
        responseformat_name = responseformat.split("(", 1)[0]
        if responseformat_name not in cls.SUPPORTED_FORMATS:
            supported = ", ".join(cls.SUPPORTED_FORMATS)
            raise ValueError(
                f"Unsupported responseformat {responseformat!r}. "
                f"Supported formats are: {supported}."
            )

    def _construct_ql_query(self, userquery, responseformat, verbosity, date):
        raw_query = str(userquery).rstrip()
        if not raw_query.endswith(";"):
            raw_query += ";"

        if date:
            date = f'[date:"{date:%Y-%m-%dT%H:%M:%SZ}"]'

        if responseformat == "geojson":
            template = self._GEOJSON_QUERY_TEMPLATE
            complete_query = template.format(
                query=raw_query, verbosity=verbosity, date=date
            )
        else:
            template = self._QUERY_TEMPLATE
            complete_query = template.format(
                query=raw_query, out=responseformat, verbosity=verbosity, date=date
            )

        if self.debug:
            print(complete_query)
        return complete_query

    def _get_from_overpass(self, query):
        payload = {"data": query}

        try:
            r = requests.post(
                self.endpoint,
                data=payload,
                timeout=self.timeout,
                proxies=self.proxies,
                headers=self.headers,
            )

        except requests.exceptions.Timeout as exc:
            raise TimeoutError(self._timeout) from exc

        self._status = r.status_code

        if self._status != 200:
            if self._status == 400:
                raise OverpassSyntaxError(query)
            elif self._status == 429:
                raise MultipleRequestsError()
            elif self._status == 504:
                raise ServerLoadError(self._timeout)
            raise UnknownOverpassError(
                f"The request returned status code {self._status}"
            )
        else:
            r.encoding = "utf-8"
            return r
